① A->next = C;
   C->prev = A;

② A->next = B->next;
   C->prev = B->prev;

③ B->prev->next = B->next;
   B->next->prev = B->prev;

④ A->next = A->next->next;
   A->next->next->prev = B->prev;

#include <stdio.h>
void funCount();
int main(void) {
    int num;
    for(num=0; num<2; num++)
        funCount();
    return 0;
}
void funCount() {
    int num=0;
    static int count;
    printf("num = %d, count = %d\n",
            ++num, count++);
}
